+  // Handle clamp pattern: icmp eq Z, min(max(Z, low), high)
+  // This is true iff low <= Z <= high
+  // If high - low + 1 is a power of 2, transform to (Z - low) ult (high - low + 1)
+  bool IsNE = (Pred == ICmpInst::ICMP_NE);
+  if (Pred == ICmpInst::ICMP_EQ || IsNE) {
+    Value *InnerVal = nullptr;
+    const APInt *Low = nullptr, *High = nullptr;
+    bool IsSignedMinMax = MinMax->isSigned();
+
+    // Check for: smin(smax(Z, low), high) or umin(umax(Z, low), high)
+    if ((IsSignedMinMax && MinMax->getIntrinsicID() == Intrinsic::smin) ||
+        (!IsSignedMinMax && MinMax->getIntrinsicID() == Intrinsic::umin)) {
+      if (auto *InnerMax = dyn_cast<MinMaxIntrinsic>(X)) {
+        if ((IsSignedMinMax && InnerMax->getIntrinsicID() == Intrinsic::smax) ||
+            (!IsSignedMinMax && InnerMax->getIntrinsicID() == Intrinsic::umax)) {
+          if (InnerMax->getOperand(0) == Z) {
+            if (match(InnerMax->getOperand(1), m_APInt(Low)) &&
+                match(Y, m_APInt(High))) {
+              InnerVal = Z;
+            }
+          }
+        }
+      }
+    }
+
+    // Check for: smin(smax(low, Z), high) or umin(umax(low, Z), high) (commuted inner)
+    if (!InnerVal &&
+        ((IsSignedMinMax && MinMax->getIntrinsicID() == Intrinsic::smin) ||
+         (!IsSignedMinMax && MinMax->getIntrinsicID() == Intrinsic::umin))) {
+      if (auto *InnerMax = dyn_cast<MinMaxIntrinsic>(X)) {
+        if ((IsSignedMinMax && InnerMax->getIntrinsicID() == Intrinsic::smax) ||
+            (!IsSignedMinMax && InnerMax->getIntrinsicID() == Intrinsic::umax)) {
+          if (InnerMax->getOperand(1) == Z) {
+            if (match(InnerMax->getOperand(0), m_APInt(Low)) &&
+                match(Y, m_APInt(High))) {
+              InnerVal = Z;
+            }
+          }
+        }
+      }
+    }
+
+    if (InnerVal) {
+      APInt RangeSize = *High - *Low + 1;
+      if (RangeSize.isPowerOf2()) {
+        // (Z - low) ult (high - low + 1)
+        Value *NewLHS = Builder.CreateSub(InnerVal,
+            ConstantInt::get(InnerVal->getType(), *Low));
+        Value *NewRHS = ConstantInt::get(InnerVal->getType(), RangeSize);
+        ICmpInst::Predicate NewPred = IsNE ? ICmpInst::ICMP_UGE : ICmpInst::ICMP_ULT;
+        return ICmpInst::Create(Instruction::ICmp, NewPred, NewLHS, NewRHS);
+      }
+    }
+  }
