  2386 |           (IID == Intrinsic::smin && Pred_t::match(ICmpInst::ICMP_SLT)) ||
  2387 |           (IID == Intrinsic::umax && Pred_t::match(ICmpInst::ICMP_UGT)) ||
  2388 |           (IID == Intrinsic::umin && Pred_t::match(ICmpInst::ICMP_ULT))) {
